I cannot generate a 3D model file directly, but I can provide you with the **complete code** to create one.

Below is a fully functional **HTML/JavaScript** script using the **Three.js** library. You can copy this code, save it as an `.html` file, and open it in any web browser to see a 3D house.

### How to use this:
1.  Copy the code block below.
2.  Create a new file on your computer named `house.html`.
3.  Paste the code into that file and save it.
4.  Double-click `house.html` to open it in your browser.

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>3D House Model</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: Arial, sans-serif;
            font-weight: bold;
            text-shadow: 1px 1px 2px black;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">Click and drag to rotate • Scroll to zoom</div>

    <!-- Import Three.js from a CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // 1. Scene Setup
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 20, 100);

        const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(15, 10, 20);

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true;
        document.body.appendChild(renderer.domElement);

        // 2. Controls
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;

        // 3. Lighting
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 2048;
        dirLight.shadow.mapSize.height = 2048;
        scene.add(dirLight);

        // 4. Building the House
        const houseGroup = new THREE.Group();

        // Materials
        const wallMaterial = new THREE.MeshStandardMaterial({ color: 0xE0E0E0 }); // White walls
        const roofMaterial = new THREE.MeshStandardMaterial({ color: 0x8B4513 }); // Brown roof
        const windowMaterial = new THREE.MeshStandardMaterial({ color: 0x87CEEB, transparent: true, opacity: 0.6 });
        const doorMaterial = new THREE.MeshStandardMaterial({ color: 0x5C4033 }); // Dark wood

        // --- Base ---
        const baseGeo = new THREE.BoxGeometry(10, 2, 10);
        const base = new THREE.Mesh(baseGeo, wallMaterial);
        base.position.y = 1;
        base.castShadow = true;
        base.receiveShadow = true;
        houseGroup.add(base);

        // --- Walls ---
        const wallGeo = new THREE.BoxGeometry(8, 6, 8);
        const walls = new THREE.Mesh(wallGeo, wallMaterial);
        walls.position.y = 1 + 3; // Sit on top of base
        walls.castShadow = true;
        walls.receiveShadow = true;
        houseGroup.add(walls);

        // --- Roof ---
        const roofGeo = new THREE.ConeGeometry(8, 4, 4);
        const roof = new THREE.Mesh(roofGeo, roofMaterial);
        roof.position.y = 1 + 3 + 2; // Sit on top of walls
        roof.rotation.y = Math.PI / 4; // Rotate to align with walls
        roof.castShadow = true;
        houseGroup.add(roof);

        // --- Windows ---
        function createWindow(x, z, y) {
            const winGeo = new THREE.BoxGeometry(1.5, 1.5, 0.2);
            const win = new THREE.Mesh(winGeo, windowMaterial);
            win.position.set(x, y, z);
            houseGroup.add(win);
        }

        createWindow(2, 1 + 3 + 0.8, 2);
        createWindow(-2, 1 + 3 + 0.8, 2);
        createWindow(2, 1 + 3 + 0.8, -2);
        createWindow(-2, 1 + 3 + 0.8, -2);

        // --- Door ---
        const doorGeo = new THREE.BoxGeometry(1.5, 3, 0.2);
        const door = new THREE.Mesh(doorGeo, doorMaterial);
        door.position.set(0, 1 + 3 + 1.5, 4); // Front center
        houseGroup.add(door);

        scene.add(houseGroup);

        // 5. Ground
        const groundGeo = new THREE.PlaneGeometry(200, 200);
        const groundMat = new THREE.MeshStandardMaterial({ color: 0x228B22 }); // Forest Green
        const ground = new THREE.Mesh(groundGeo, groundMat);
        ground.rotation.x = -Math.PI / 2;
        ground.receiveShadow = true;
        scene.add(ground);

        // 6. Animation Loop
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        // Handle window resize
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });

        animate();
    </script>
</body>
</html>
```

### What this code does:
1.  **Sets up the Scene:** Creates a 3D environment with a sky-blue background and fog.
2.  **Lighting:** Adds a directional light (sun) that casts shadows and an ambient light for general visibility.
3.  **Geometry:**
    *   **Base:** A thick box for the foundation.
    *   **Walls:** A box sitting on top of the base.
    *   **Roof:** A cone rotated to look like a pyramid roof.
    *   **Details:** Adds 4 windows and 1 door using smaller boxes.
4.  **Interactivity:** Includes `OrbitControls`, allowing you to click and drag to rotate around the house and scroll to zoom in/out.

### If you need a file format (OBJ/FBX):
If you need to import this into Blender, Unity, or Unreal Engine, you cannot use the code above directly. You would need to:
1.  Use a 3D modeling software (like Blender).
2.  Create the shapes manually.
3.  Export the file as `.obj` or `.fbx`.
4.  Import that file into your game engine.
